const items = $input.all();
const normalized = [];

for (const item of items) {
  const email = item.json;

  let body = email.text || email.snippet || '';

  if (!body && email.html) {
    body = email.html.replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();
  }

  const sigPatterns = [/\n--\s*\n[\s\S]*$/, /\nSent from [\s\S]*$/, /\n_{3,}[\s\S]*$/, /\nGet Outlook[\s\S]*$/];
  for (const pattern of sigPatterns) {
    body = body.replace(pattern, '');
  }

  body = body.replace(/\nOn .* wrote:[\s\S]*$/m, '');
  body = body.split('\n').filter(line => !line.startsWith('>')).join('\n');

  if (body.length > 2000) {
    body = body.substring(0, 2000) + '... [truncated]';
  }

  const attachmentNames = [];
  if (email.payload && email.payload.parts) {
    for (const part of email.payload.parts) {
      if (part.filename && part.filename.length > 0) {
        attachmentNames.push(part.filename);
      }
    }
  }

  if (attachmentNames.length > 0) {
    body += '\n[Attachments: ' + attachmentNames.join(', ') + ']';
  }

  let bodyHtml = '';
  if (email.html) {
    bodyHtml = email.html.substring(0, 500);
  }

  normalized.push({
    json: {
      id: email.id || email.messageId || '',
      source: 'gmail',
      from: {
        name: email.from ? email.from.split('<')[0].trim().replace(/"/g, '') : '',
        email: email.from ? (email.from.match(/<(.+?)>/) || ['', email.from])[1] : ''
      },
      to: (email.to || '').split(',').map(t => ({
        name: t.split('<')[0].trim().replace(/"/g, ''),
        email: (t.match(/<(.+?)>/) || ['', t.trim()])[1]
      })),
      subject: email.subject || '(no subject)',
      body: body,
      bodyHtml: bodyHtml,
      date: email.date || new Date(parseInt(email.internalDate)).toISOString(),
      labels: email.labelIds || [],
      isRead: !(email.labelIds || []).includes('UNREAD'),
      hasAttachments: attachmentNames.length > 0,
      attachmentNames: attachmentNames,
      threadId: email.threadId || '',
      messageCount: 1
    }
  });
}

return normalized.length > 0 ? normalized : [{ json: { emails: [], count: 0 } }];
